#!/usr/bin/env python3
"""Block `pnpm test` (interactive watcher); steer Claude to `pnpm test:ci`."""
import json, sys

def main():
    try:
        ev = json.load(sys.stdin)
    except Exception:
        return 0  # never break Claude Code on bad input

    if ev.get("tool_name") != "Bash":
        return 0

    tool_input = ev.get("tool_input") or {}
    command = tool_input.get("command", "")

    # Check for the known interactive watcher trap
    if command.strip().startswith("pnpm test") and "test:ci" not in command:
        print("\n[Guardrail] Warning: Running `pnpm test` often starts an interactive watcher and may time out. Please use `pnpm test:ci` instead, as defined in package.json, for non-interactive CI runs.", file=sys.stderr)
        return 2  # Block the command

    return 0

if __name__ == "__main__":
    sys.exit(main())

