#!/usr/bin/env python3
import json, sys

def main():
    try:
        ev = json.load(sys.stdin)
    except Exception:
        return 0  # never break Claude Code on bad input

    if ev.get("tool_name") != "Bash":
        return 0

    tool_input = ev.get("tool_input") or {}
    command = tool_input.get("command", "").strip()

    # Check if the command is ruff check
    if command.startswith("ruff check"):
        print("\n⚠️ Warning: Before running `ruff check`, please run `ruff format` first. `ruff check` will report formatting errors (like indentation) that `ruff format` will automatically fix.", file=sys.stderr)
        return 2  # Block the tool call

    return 0

if __name__ == "__main__":
    sys.exit(main())
